import React, { useState, useEffect } from 'react';
import { useTranslation } from 'react-i18next';
import { connectMT5, disconnectMT5, getMT5Status } from '../services/api';
import { useMT5 } from '../context/MT5Context';
import './MT5Connection.css';

function MT5Connection() {
  const { t } = useTranslation();
  const {
    isConnected,
    accountInfo,
    loading: mt5Loading,
    checkConnection,
    setIsConnected,
    setAccountInfo,
  } = useMT5();
  const [login, setLogin] = useState('108891758');
  const [password, setPassword] = useState('TcM!5aVt');
  const [server, setServer] = useState('MetaQuotes-Demo');
  const [isLoading, setIsLoading] = useState(false);

  const handleConnect = async (e) => {
    e.preventDefault();
    setIsLoading(true);
    try {
      const result = await connectMT5(parseInt(login), password, server);
      if (result.success) {
        setIsConnected(true);
        setAccountInfo(result.debug_info?.account_info);
        alert(t('mt5Connection.connectedSuccess'));
      }
    } catch (error) {
      console.error('Connection failed:', error);
      const errorDetail = error.response?.data?.detail || error.message;
      alert(t('mt5Connection.connectionFailed') + ': ' + errorDetail);
    } finally {
      setIsLoading(false);
    }
  };

  const handleDisconnect = async () => {
    setIsLoading(true);
    try {
      await disconnectMT5();
      setIsConnected(false);
      setAccountInfo(null);
      alert(t('mt5Connection.disconnectedSuccess'));
    } catch (error) {
      console.error('Disconnect failed:', error);
    } finally {
      setIsLoading(false);
    }
  };

  const handleTestConnection = async (e) => {
    e.preventDefault();
    setIsLoading(true);
    try {
      const result = await connectMT5(parseInt(login), password, server);
      if (result.success) {
        alert('Test connection successful!');
        await disconnectMT5();
        setIsConnected(false);
        setAccountInfo(null);
      }
    } catch (error) {
      console.error('Test connection failed:', error);
      const errorDetail = error.response?.data?.detail || error.message;
      alert(t('mt5Connection.testFailed') + ': ' + errorDetail);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="mt5-connection">
      <h1>{t('mt5Connection.title')}</h1>
      
      <div className="connection-container">
        {!isConnected ? (
          <form onSubmit={handleConnect} className="connection-form">
            <div className="form-group">
              <label>{t('mt5Connection.accountLogin')}</label>
              <input
                type="number"
                value={login}
                onChange={(e) => setLogin(e.target.value)}
                placeholder={t('mt5Connection.accountLogin')}
                required
              />
            </div>
            <div className="form-group">
              <label>{t('mt5Connection.password')}</label>
              <input
                type="password"
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                placeholder={t('mt5Connection.password')}
                required
              />
            </div>
            <div className="form-group">
              <label>{t('mt5Connection.brokerServer')}</label>
              <input
                type="text"
                value={server}
                onChange={(e) => setServer(e.target.value)}
                placeholder={t('mt5Connection.brokerServer')}
                required
              />
            </div>
            <div className="button-group">
              <button type="submit" disabled={isLoading} className="btn-primary">
                {isLoading ? t('mt5Connection.connecting') : t('mt5Connection.connect')}
              </button>
              <button 
                type="button" 
                onClick={handleTestConnection} 
                disabled={isLoading}
                className="btn-secondary"
              >
                {t('mt5Connection.testConnection')}
              </button>
            </div>
          </form>
        ) : (
          <div className="account-info">
            <div className="status-badge connected">
              ● {t('dashboard.statusConnected')}
            </div>
            
            {accountInfo && (
              <div className="account-details">
                <div className="detail-row">
                  <span className="detail-label">{t('mt5Connection.accountNumber')}:</span>
                  <span className="detail-value">{accountInfo.login}</span>
                </div>
                <div className="detail-row">
                  <span className="detail-label">{t('mt5Connection.accountName')}:</span>
                  <span className="detail-value">{accountInfo.name}</span>
                </div>
                <div className="detail-row">
                  <span className="detail-label">{t('mt5Connection.server')}:</span>
                  <span className="detail-value">{accountInfo.server}</span>
                </div>
                <div className="detail-row">
                  <span className="detail-label">{t('dashboard.balance')}:</span>
                  <span className="detail-value">${accountInfo.balance?.toFixed(2)}</span>
                </div>
                <div className="detail-row">
                  <span className="detail-label">{t('dashboard.equity')}:</span>
                  <span className="detail-value">${accountInfo.equity?.toFixed(2)}</span>
                </div>
                <div className="detail-row">
                  <span className="detail-label">{t('dashboard.margin')}:</span>
                  <span className="detail-value">${accountInfo.margin?.toFixed(2)}</span>
                </div>
                <div className="detail-row">
                  <span className="detail-label">{t('mt5Connection.connectionStatus')}:</span>
                  <span className="detail-value status-online">{t('mt5Connection.statusOnline')}</span>
                </div>
              </div>
            )}
            
            <button 
              onClick={handleDisconnect} 
              disabled={isLoading}
              className="btn-danger"
            >
              {isLoading ? 'Disconnecting...' : t('mt5Connection.disconnect')}
            </button>
          </div>
        )}
      </div>
    </div>
  );
}

export default MT5Connection;
